mapper.select:
SELECT a.apply_uuid, a.uuid AS approve_uuid, a.leader_uuid, l.leader_name AS leader_name, a.`order`, a.status, CASE a.status WHEN 0 THEN '删除' WHEN 1 THEN '通过' WHEN 3 THEN '驳回' WHEN 4 THEN '待审批' WHEN 5 THEN '审批中' WHEN 9 THEN '审批通过' END AS status_name FROM approve a LEFT JOIN leader l ON a.leader_uuid = l.leader_uuid WHERE a.apply_uuid IN
#{applyUuid}
AND a.is_delete = 1 ORDER BY a.`order` ASC
